/* mountainview-ui theme — Material Design 3 tokens for Tailwind CSS v4.
   Import after tailwindcss:
     @import "tailwindcss";
     @import "./theme.css";                                        */

@custom-variant dark (&:where(.dark, .dark *));

/* ------------------------------------------------------------------ */
/* M3 baseline color scheme — light                                    */
/* Values from the Material 3 baseline palette.                        */
/* ------------------------------------------------------------------ */
:root {
  --primary: #6750a4;
  --on-primary: #ffffff;
  --primary-container: #eaddff;
  --on-primary-container: #4f378b;

  --secondary: #625b71;
  --on-secondary: #ffffff;
  --secondary-container: #e8def8;
  --on-secondary-container: #4a4458;

  --tertiary: #7d5260;
  --on-tertiary: #ffffff;
  --tertiary-container: #ffd8e4;
  --on-tertiary-container: #633b48;

  --error: #b3261e;
  --on-error: #ffffff;
  --error-container: #f9dedc;
  --on-error-container: #852221;

  --surface: #fef7ff;
  --surface-dim: #ded8e1;
  --surface-bright: #fef7ff;
  --surface-container-lowest: #ffffff;
  --surface-container-low: #f7f2fa;
  --surface-container: #f3edf7;
  --surface-container-high: #ece6f0;
  --surface-container-highest: #e6e0e9;
  --on-surface: #1d1b20;
  --on-surface-variant: #49454f;
  --surface-variant: #e7e0ec;

  --inverse-surface: #322f35;
  --inverse-on-surface: #f5eff7;
  --inverse-primary: #d0bcff;

  --outline: #79747e;
  --outline-variant: #cac4d0;
  --scrim: #000000;
  --shadow-color: #000000;
}

/* M3 baseline color scheme — dark */
.dark {
  --primary: #d0bcff;
  --on-primary: #381e72;
  --primary-container: #4f378b;
  --on-primary-container: #eaddff;

  --secondary: #ccc2dc;
  --on-secondary: #332d41;
  --secondary-container: #4a4458;
  --on-secondary-container: #e8def8;

  --tertiary: #efb8c8;
  --on-tertiary: #492532;
  --tertiary-container: #633b48;
  --on-tertiary-container: #ffd8e4;

  --error: #f2b8b5;
  --on-error: #601410;
  --error-container: #8c1d18;
  --on-error-container: #f9dedc;

  --surface: #141218;
  --surface-dim: #141218;
  --surface-bright: #3b383e;
  --surface-container-lowest: #0f0d13;
  --surface-container-low: #1d1b20;
  --surface-container: #211f26;
  --surface-container-high: #2b2930;
  --surface-container-highest: #36343b;
  --on-surface: #e6e0e9;
  --on-surface-variant: #cac4d0;
  --surface-variant: #49454f;

  --inverse-surface: #e6e0e9;
  --inverse-on-surface: #322f35;
  --inverse-primary: #6750a4;

  --outline: #938f99;
  --outline-variant: #49454f;
  --scrim: #000000;
  --shadow-color: #000000;
}

@theme inline {
  --font-sans: Roboto, "Google Sans", "Helvetica Neue", system-ui, sans-serif;
  --font-mono: "Roboto Mono", ui-monospace, Menlo, monospace;

  --color-primary: var(--primary);
  --color-on-primary: var(--on-primary);
  --color-primary-container: var(--primary-container);
  --color-on-primary-container: var(--on-primary-container);

  --color-secondary: var(--secondary);
  --color-on-secondary: var(--on-secondary);
  --color-secondary-container: var(--secondary-container);
  --color-on-secondary-container: var(--on-secondary-container);

  --color-tertiary: var(--tertiary);
  --color-on-tertiary: var(--on-tertiary);
  --color-tertiary-container: var(--tertiary-container);
  --color-on-tertiary-container: var(--on-tertiary-container);

  --color-error: var(--error);
  --color-on-error: var(--on-error);
  --color-error-container: var(--error-container);
  --color-on-error-container: var(--on-error-container);

  --color-surface: var(--surface);
  --color-surface-dim: var(--surface-dim);
  --color-surface-bright: var(--surface-bright);
  --color-surface-lowest: var(--surface-container-lowest);
  --color-surface-low: var(--surface-container-low);
  --color-surface-container: var(--surface-container);
  --color-surface-high: var(--surface-container-high);
  --color-surface-highest: var(--surface-container-highest);
  --color-on-surface: var(--on-surface);
  --color-on-surface-variant: var(--on-surface-variant);
  --color-surface-variant: var(--surface-variant);

  --color-inverse-surface: var(--inverse-surface);
  --color-inverse-on-surface: var(--inverse-on-surface);
  --color-inverse-primary: var(--inverse-primary);

  --color-outline: var(--outline);
  --color-outline-variant: var(--outline-variant);
  --color-scrim: var(--scrim);

  /* M3 shape scale */
  --radius-xs: 4px;
  --radius-sm: 8px;
  --radius-md: 12px;
  --radius-lg: 16px;
  --radius-xl: 28px;

  /* M3 elevation (umbra + penumbra) */
  --shadow-elevation-1: 0 1px 2px rgba(0, 0, 0, 0.3),
    0 1px 3px 1px rgba(0, 0, 0, 0.15);
  --shadow-elevation-2: 0 1px 2px rgba(0, 0, 0, 0.3),
    0 2px 6px 2px rgba(0, 0, 0, 0.15);
  --shadow-elevation-3: 0 1px 3px rgba(0, 0, 0, 0.3),
    0 4px 8px 3px rgba(0, 0, 0, 0.15);
  --shadow-elevation-4: 0 2px 3px rgba(0, 0, 0, 0.3),
    0 6px 10px 4px rgba(0, 0, 0, 0.15);
  --shadow-elevation-5: 0 4px 4px rgba(0, 0, 0, 0.3),
    0 8px 12px 6px rgba(0, 0, 0, 0.15);

  --ease-emphasized: cubic-bezier(0.2, 0, 0, 1);
  --ease-emphasized-decelerate: cubic-bezier(0.05, 0.7, 0.1, 1);
}

/* ------------------------------------------------------------------ */
/* M3 type scale (size / line-height / tracking / weight)              */
/* ------------------------------------------------------------------ */
@utility text-display-l {
  font-size: 57px;
  line-height: 64px;
  letter-spacing: -0.25px;
  font-weight: 400;
}
@utility text-display-m {
  font-size: 45px;
  line-height: 52px;
  letter-spacing: 0;
  font-weight: 400;
}
@utility text-display-s {
  font-size: 36px;
  line-height: 44px;
  letter-spacing: 0;
  font-weight: 400;
}
@utility text-headline-l {
  font-size: 32px;
  line-height: 40px;
  letter-spacing: 0;
  font-weight: 400;
}
@utility text-headline-m {
  font-size: 28px;
  line-height: 36px;
  letter-spacing: 0;
  font-weight: 400;
}
@utility text-headline-s {
  font-size: 24px;
  line-height: 32px;
  letter-spacing: 0;
  font-weight: 400;
}
@utility text-title-l {
  font-size: 22px;
  line-height: 28px;
  letter-spacing: 0;
  font-weight: 400;
}
@utility text-title-m {
  font-size: 16px;
  line-height: 24px;
  letter-spacing: 0.15px;
  font-weight: 500;
}
@utility text-title-s {
  font-size: 14px;
  line-height: 20px;
  letter-spacing: 0.1px;
  font-weight: 500;
}
@utility text-body-l {
  font-size: 16px;
  line-height: 24px;
  letter-spacing: 0.5px;
  font-weight: 400;
}
@utility text-body-m {
  font-size: 14px;
  line-height: 20px;
  letter-spacing: 0.25px;
  font-weight: 400;
}
@utility text-body-s {
  font-size: 12px;
  line-height: 16px;
  letter-spacing: 0.4px;
  font-weight: 400;
}
@utility text-label-l {
  font-size: 14px;
  line-height: 20px;
  letter-spacing: 0.1px;
  font-weight: 500;
}
@utility text-label-m {
  font-size: 12px;
  line-height: 16px;
  letter-spacing: 0.5px;
  font-weight: 500;
}
@utility text-label-s {
  font-size: 11px;
  line-height: 16px;
  letter-spacing: 0.5px;
  font-weight: 500;
}

/* ------------------------------------------------------------------ */
/* State layers — hover 8%, press 12% of the content color.            */
/* Apply on interactive surfaces; color-mix keeps the base intact.     */
/* ------------------------------------------------------------------ */
@utility state-on-primary {
  &:hover {
    background-color: color-mix(in srgb, var(--on-primary) 8%, var(--primary));
  }
  &:active {
    background-color: color-mix(in srgb, var(--on-primary) 12%, var(--primary));
  }
}
@utility state-on-surface {
  &:hover {
    background-color: color-mix(in srgb, var(--on-surface) 8%, transparent);
  }
  &:active {
    background-color: color-mix(in srgb, var(--on-surface) 12%, transparent);
  }
}
@utility state-on-secondary-container {
  &:hover {
    background-color: color-mix(
      in srgb,
      var(--on-secondary-container) 8%,
      var(--secondary-container)
    );
  }
  &:active {
    background-color: color-mix(
      in srgb,
      var(--on-secondary-container) 12%,
      var(--secondary-container)
    );
  }
}
@utility state-primary {
  &:hover {
    background-color: color-mix(in srgb, var(--primary) 8%, transparent);
  }
  &:active {
    background-color: color-mix(in srgb, var(--primary) 12%, transparent);
  }
}

import { clsx, type ClassValue } from "clsx";
import { extendTailwindMerge } from "tailwind-merge";

// Teach tailwind-merge the M3 type-scale utilities so `text-title-m`
// (a font-size) never collides with `text-on-primary` (a color).
const twMerge = extendTailwindMerge({
  extend: {
    classGroups: {
      "font-size": [
        {
          text: [
            "display-l", "display-m", "display-s",
            "headline-l", "headline-m", "headline-s",
            "title-l", "title-m", "title-s",
            "body-l", "body-m", "body-s",
            "label-l", "label-m", "label-s",
          ],
        },
      ],
    },
  },
});

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}
